// Generated by AI (UnitTest MCP)
import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { EventEmitter } from "node:events";
import { PassThrough, Writable } from "node:stream";

import { afterEach, describe, expect, it, vi } from "vitest";
import { parse } from "jsonc-parser";

import {
  install,
  parseArguments,
  registrations,
  smokeServer,
  updateGitignore,
  updateMcpConfig,
} from "./install.mjs";

const temporaryDirectories = [];

afterEach(() => {
  for (const directory of temporaryDirectories.splice(0)) {
    fs.rmSync(directory, { recursive: true, force: true });
  }
});

describe("registrations", () => {
  it("uses literal workspace paths and platform-specific executables", () => {
    const windows = registrations("v1.2.3", "win32", "copilot");
    const linux = registrations("v1.2.3", "linux", "agent-a");

    expect(windows.mindleak.command).toBe(
      "${workspaceFolder}/.mindleak/bin/v1.2.3/mindleak-mcp.exe"
    );
    expect(windows.lodestar.command).toContain("lodestar-mcp.exe");
    expect(windows.mindleak.env.MINDLEAK_AGENT).toBe("copilot");
    expect(linux.mindleak.command.endsWith("mindleak-mcp")).toBe(true);
    expect(linux.lodestar.env.LODESTAR_AGENT).toBe("agent-a");
  });

  it("rejects path-like versions", () => {
    expect(() => registrations("../../latest", "linux", "copilot")).toThrow(
      "invalid release version"
    );
  });
});

describe("updateMcpConfig", () => {
  it("preserves comments and unrelated servers while replacing MindLeak entries", () => {
    const source = `{
  // Keep this registration.
  "servers": {
    "other": { "command": "other-server" },
    "mindleak": { "command": "old" },
  },
}
`;

    const result = updateMcpConfig(source, registrations("v1.2.3", "linux", "copilot"));
    const parsed = parse(result);

    expect(result).toContain("// Keep this registration.");
    expect(parsed.servers.other.command).toBe("other-server");
    expect(parsed.servers.mindleak.command).toContain("v1.2.3/mindleak-mcp");
    expect(parsed.servers.lodestar.command).toContain("v1.2.3/lodestar-mcp");
  });

  it("creates a valid document from an empty source and rejects malformed JSONC", () => {
    expect(
      parse(updateMcpConfig("", registrations("v1.0.0", "linux", "a"))).servers
    ).toHaveProperty("mindleak");
    expect(() => updateMcpConfig("{ nope", {})).toThrow("cannot update .vscode/mcp.json");
    expect(() => updateMcpConfig("[]", {})).toThrow("root must be an object");
  });
});

describe("updateGitignore", () => {
  it("adds privacy rules once without removing existing content", () => {
    const first = updateGitignore("node_modules/\n");
    const second = updateGitignore(first);

    expect(first).toContain("node_modules/");
    expect(first).toContain(".mindleak/");
    expect(first).toContain("!.lodestar/CONSTITUTION.md");
    expect(second).toBe(first);
  });
});

describe("parseArguments", () => {
  it("parses explicit options and rejects missing values", () => {
    const options = parseArguments(
      ["--workspace", "project", "--agent", "agent-a", "--version", "v1.2.3", "--force"],
      "/root"
    );

    expect(options.workspace).toBe(path.resolve("/root", "project"));
    expect(options.agent).toBe("agent-a");
    expect(options.version).toBe("v1.2.3");
    expect(options.force).toBe(true);
    expect(() => parseArguments(["--workspace"], "/root")).toThrow("requires a value");
    expect(() => parseArguments(["--unknown"], "/root")).toThrow("unknown argument");
    expect(() => parseArguments(["--agent", " "], "/root")).toThrow("must not be empty");
    expect(parseArguments(["--help"], "/root").help).toBe(true);
  });
});

describe("install", () => {
  it("stages both servers, preserves JSONC, and is idempotent", async () => {
    const root = temporaryDirectory();
    const archive = path.join(root, "archive");
    const workspace = path.join(root, "workspace");
    fs.mkdirSync(archive, { recursive: true });
    fs.mkdirSync(path.join(workspace, ".vscode"), { recursive: true });
    fs.writeFileSync(path.join(archive, "VERSION"), "v1.2.3\n");
    fs.writeFileSync(path.join(archive, "mindleak-mcp.exe"), "memory");
    fs.writeFileSync(path.join(archive, "lodestar-mcp.exe"), "intent");
    fs.writeFileSync(
      path.join(workspace, ".vscode", "mcp.json"),
      '{\n  // preserved\n  "servers": { "other": { "command": "other" } }\n}\n'
    );
    fs.writeFileSync(path.join(workspace, ".gitignore"), "target/\n");
    const smokedDirectories = [];
    const runtime = {
      platform: "win32",
      executableExtension: ".exe",
      smoke: async (directory) => smokedDirectories.push(directory),
    };
    const options = { workspace, agent: "agent-a", force: false };

    await install(options, archive, runtime);
    await install(options, archive, runtime);

    const installed = path.join(workspace, ".mindleak", "bin", "v1.2.3");
    expect(fs.readFileSync(path.join(installed, "mindleak-mcp.exe"), "utf8")).toBe("memory");
    expect(fs.readFileSync(path.join(installed, "lodestar-mcp.exe"), "utf8")).toBe("intent");
    expect(smokedDirectories).toEqual([expect.stringContaining(".partial-"), installed]);
    const config = fs.readFileSync(path.join(workspace, ".vscode", "mcp.json"), "utf8");
    expect(config).toContain("// preserved");
    expect(parse(config).servers.other.command).toBe("other");
    expect(parse(config).servers.mindleak.env.MINDLEAK_AGENT).toBe("agent-a");
    expect(fs.readFileSync(path.join(workspace, ".gitignore"), "utf8")).toContain(".lodestar/*");
  });

  it("replaces an existing version only when forced", async () => {
    const root = temporaryDirectory();
    const archive = path.join(root, "archive");
    const workspace = path.join(root, "workspace");
    const installed = path.join(workspace, ".mindleak", "bin", "v1.2.3");
    fs.mkdirSync(archive, { recursive: true });
    fs.mkdirSync(installed, { recursive: true });
    fs.writeFileSync(path.join(archive, "mindleak-mcp.exe"), "new-memory");
    fs.writeFileSync(path.join(archive, "lodestar-mcp.exe"), "new-intent");
    fs.writeFileSync(path.join(installed, "mindleak-mcp.exe"), "old-memory");
    fs.writeFileSync(path.join(installed, "lodestar-mcp.exe"), "old-intent");

    await install({ workspace, agent: "copilot", version: "v1.2.3", force: true }, archive, {
      platform: "win32",
      executableExtension: ".exe",
      smoke: async () => undefined,
    });

    expect(fs.readFileSync(path.join(installed, "mindleak-mcp.exe"), "utf8")).toBe("new-memory");
    expect(fs.existsSync(`${installed}.previous-${process.pid}`)).toBe(false);
  });

  it("does not register an incomplete release archive", async () => {
    const root = temporaryDirectory();
    const archive = path.join(root, "archive");
    const workspace = path.join(root, "workspace");
    fs.mkdirSync(archive, { recursive: true });
    fs.writeFileSync(path.join(archive, "mindleak-mcp.exe"), "memory");

    await expect(
      install({ workspace, agent: "copilot", version: "v1.2.3", force: false }, archive, {
        platform: "win32",
        executableExtension: ".exe",
        smoke: async () => undefined,
      })
    ).rejects.toThrow("missing lodestar-mcp.exe");
    expect(fs.existsSync(path.join(workspace, ".vscode", "mcp.json"))).toBe(false);
  });
});

describe("smokeServer", () => {
  it("completes initialize and tools/list before stopping the child", async () => {
    const fake = fakeMcpProcess((request) =>
      request.id === 1
        ? { jsonrpc: "2.0", id: 1, result: { protocolVersion: "2024-11-05" } }
        : { jsonrpc: "2.0", id: 2, result: { tools: [{ name: "graph_stats" }] } }
    );
    const spawnProcess = vi.fn(() => fake.child);

    await smokeServer("mindleak-mcp", "MINDLEAK_DB", spawnProcess, 100);

    expect(spawnProcess).toHaveBeenCalledWith(
      "mindleak-mcp",
      [],
      expect.objectContaining({ env: expect.objectContaining({ MINDLEAK_DB: ":memory:" }) })
    );
    expect(fake.requests.map((request) => request.method)).toEqual(["initialize", "tools/list"]);
    expect(fake.child.kill).toHaveBeenCalledOnce();
  });

  it("waits for the smoke child to exit before releasing staged binaries", async () => {
    // Windows locks a running executable. Returning at MCP readiness made the
    // following staging rename intermittently fail with EPERM; child exit is
    // the point at which the installer may safely move the directory.
    const fake = fakeMcpProcess(
      (request) =>
        request.id === 1
          ? { id: 1, result: {} }
          : { id: 2, result: { tools: [{ name: "graph_stats" }] } },
      false
    );
    let completed = false;
    const smoke = smokeServer("mindleak-mcp", "MINDLEAK_DB", () => fake.child, 100).then(() => {
      completed = true;
    });

    await vi.waitFor(() => expect(fake.child.kill).toHaveBeenCalledOnce());
    await Promise.resolve();
    expect(completed).toBe(false);
    fake.child.emit("exit", 0);
    await smoke;
    expect(completed).toBe(true);
  });

  it("rejects invalid JSON, empty tools, MCP errors, and early exits", async () => {
    const invalid = fakeMcpProcess(() => "not json");
    await expect(smokeServer("bad", "MINDLEAK_DB", () => invalid.child, 100)).rejects.toThrow(
      "invalid JSON"
    );

    const empty = fakeMcpProcess((request) =>
      request.id === 1 ? { id: 1, result: {} } : { id: 2, result: { tools: [] } }
    );
    await expect(smokeServer("empty", "MINDLEAK_DB", () => empty.child, 100)).rejects.toThrow(
      "returned no MCP tools"
    );

    const protocolError = fakeMcpProcess(() => ({ id: 1, error: { code: -1 } }));
    await expect(
      smokeServer("error", "MINDLEAK_DB", () => protocolError.child, 100)
    ).rejects.toThrow("returned");

    const earlyExit = fakeMcpProcess(() => undefined);
    queueMicrotask(() => earlyExit.child.emit("exit", 2));
    await expect(smokeServer("early", "MINDLEAK_DB", () => earlyExit.child, 100)).rejects.toThrow(
      "exited before MCP ready"
    );
  });
});

function temporaryDirectory() {
  const directory = fs.mkdtempSync(path.join(os.tmpdir(), "mindleak-installer-"));
  temporaryDirectories.push(directory);
  return directory;
}

function fakeMcpProcess(respond, exitOnKill = true) {
  const child = new EventEmitter();
  child.stdout = new PassThrough();
  child.stderr = new PassThrough();
  child.kill = vi.fn(() => {
    if (exitOnKill) {
      queueMicrotask(() => child.emit("exit", 0));
    }
    return true;
  });
  const requests = [];
  child.stdin = new Writable({
    write(chunk, _encoding, callback) {
      const request = JSON.parse(chunk.toString());
      requests.push(request);
      const response = respond(request);
      if (response !== undefined) {
        queueMicrotask(() => {
          child.stdout.write(
            `${typeof response === "string" ? response : JSON.stringify(response)}\n`
          );
        });
      }
      callback();
    },
  });
  return { child, requests };
}
